package com.google.gson.examples.android.model;

import static org.junit.jupiter.api.Assertions.assertEquals;

import org.junit.jupiter.api.Test;

import java.lang.reflect.Method;

class LineItemTest {

  @Test
  void testGetQuantity() throws Exception {
    // Using reflection to invoke getQuantity (even if public, per instructions)
    LineItem lineItem = new LineItem("TestItem", 5, 1000L, "USD");

    // Reflectively get the getQuantity method
    Method method = Class.forName("com.google.gson.examples.android.model.LineItem").getDeclaredMethod("getQuantity");
    method.setAccessible(true);

    int quantity = (int) method.invoke(lineItem);

    assertEquals(5, quantity);
  }
}
